class Solution:
    def canSplitArray(self, nums: List[int], m: int) -> bool:
        n = len(nums)
        # If the array length is 1, it's already split
        if n == 1:
            return True

        # Check if every adjacent pair has a sum >= m
        for i in range(n - 1):
            if nums[i] + nums[i + 1] < m:
                return False
        return True
